let count = 0;
const btn = document.querySelector("#counter");

btn.addEventListener("click", () => {
  count++;
  btn.textContent = `نقرت ${count} مرة`;
});

const box = document.querySelector("#hoverbox");
box.addEventListener("mouseenter", () => box.style.background = "#bbf7d0");
box.addEventListener("mouseleave", () => box.style.background = "#e0e7ff");

const field = document.querySelector("#live");
const out = document.querySelector("#out");
field.addEventListener("input", () => {
  out.textContent = "تكتب الآن: " + field.value;
});
